143→    MessagingController(Context context, NotificationController notificationController,
144→            NotificationStrategy notificationStrategy, LocalStoreProvider localStoreProvider,
145→            BackendManager backendManager, Preferences preferences, MessageStoreManager messageStoreManager,
146→            SaveMessageDataCreator saveMessageDataCreator, SpecialLocalFoldersCreator specialLocalFoldersCreator,
147→            LocalDeleteOperationDecider localDeleteOperationDecider, List<ControllerExtension> controllerExtensions) {
148→        this.context = context;
149→        this.notificationController = notificationController;
150→        this.notificationStrategy = notificationStrategy;
151→        this.localStoreProvider = localStoreProvider;
152→        this.backendManager = backendManager;
153→        this.preferences = preferences;
154→        this.messageStoreManager = messageStoreManager;
155→        this.saveMessageDataCreator = saveMessageDataCreator;
156→        this.specialLocalFoldersCreator = specialLocalFoldersCreator;
157→        this.localDeleteOperationDecider = localDeleteOperationDecider;
158→
159→        controllerThread = new Thread(new Runnable() {
160→            @Override
161→            public void run() {
162→                runInBackground();
163→            }
164→        });
165→        controllerThread.setName("MessagingController");
166→        controllerThread.start();
167→        addListener(memorizingMessagingListener);
168→
169→        initializeControllerExtensions(controllerExtensions);
170→
171→        draftOperations = new DraftOperations(this, messageStoreManager, saveMessageDataCreator);
172→        notificationOperations = new NotificationOperations(notificationController, preferences, messageStoreManager);
173→        archiveOperations = new ArchiveOperations(this);
174→    }
