176→    private void initializeControllerExtensions(List<ControllerExtension> controllerExtensions) {
177→        if (controllerExtensions.isEmpty()) {
178→            return;
179→        }
180→
181→        ControllerInternals internals = new ControllerInternals() {
182→            @Override
183→            public void put(@NotNull String description, @Nullable MessagingListener listener,
184→                    @NotNull Runnable runnable) {
185→                MessagingController.this.put(description, listener, runnable);
186→            }
187→
188→            @Override
189→            public void putBackground(@NotNull String description, @Nullable MessagingListener listener,
190→                    @NotNull Runnable runnable) {
191→                MessagingController.this.putBackground(description, listener, runnable);
192→            }
193→        };
194→
195→        for (ControllerExtension extension : controllerExtensions) {
196→            extension.init(this, backendManager, internals);
197→        }
198→    }
199→
200→    @VisibleForTesting
201→    void stop() throws InterruptedException {
202→        stopped = true;
203→        controllerThread.interrupt();
204→        controllerThread.join(1000L);
205→    }
206→
207→    private void runInBackground() {
208→        Process.setThreadPriority(Process.THREAD_PRIORITY_BACKGROUND);
209→        while (!stopped) {
210→            String commandDescription = null;
211→            try {
212→                final Command command = queuedCommands.take();
213→
214→                if (command != null) {
215→                    commandDescription = command.description;
216→
217→                    Timber.i("Running command '%s', seq = %s (%s priority)",
218→                            command.description,
219→                            command.sequence,
220→                            command.isForegroundPriority ? "foreground" : "background");
221→
222→                    command.runnable.run();
223→
224→                    Timber.i(" Command '%s' completed", command.description);
225→                }
226→            } catch (Exception e) {
227→                Timber.e(e, "Error running command '%s'", commandDescription);
228→            }
229→        }
230→    }
231→
232→    private void put(String description, MessagingListener listener, Runnable runnable) {
233→        putCommand(queuedCommands, description, listener, runnable, true);
234→    }
235→
236→    void putBackground(String description, MessagingListener listener, Runnable runnable) {
237→        putCommand(queuedCommands, description, listener, runnable, false);
238→    }
239→
240→    private void putCommand(BlockingQueue<Command> queue, String description, MessagingListener listener,
241→            Runnable runnable, boolean isForeground) {
242→        int retries = 10;
243→        Exception e = null;
244→        while (retries-- > 0) {
245→            try {
246→                Command command = new Command();
247→                command.listener = listener;
248→                command.runnable = runnable;
249→                command.description = description;
250→                command.isForegroundPriority = isForeground;
251→                queue.put(command);
252→                return;
253→            } catch (InterruptedException ie) {
254→                SystemClock.sleep(200);
255→                e = ie;
256→            }
257→        }
258→        throw new Error(e);
259→    }
