{"content":"package com.fsck.k9.controller

import app.k9mail.legacy.account.Account
import app.k9mail.legacy.message.controller.MessageReference
import com.fsck.k9.controller.MessagingController.MessageActor
import com.fsck.k9.controller.MessagingController.MoveOrCopyFlavor
import com.fsck.k9.mail.Flag
import com.fsck.k9.mailstore.LocalFolder
import com.fsck.k9.mailstore.LocalMessage
import org.junit.Before
import org.junit.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.doAnswer
import org.mockito.kotlin.eq
import org.mockito.kotlin.mock
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import org.mockito.kotlin.never

class ArchiveOperationsTest {
    private val messagingController = mock<MessagingController>()
    private val account = mock<Account>()
    private val localMessage = mock<LocalMessage>()
    private val localFolder = mock<LocalFolder>()

    private lateinit var archiveOperations: ArchiveOperations

    @Before
    fun setUp() {
        archiveOperations = ArchiveOperations(messagingController)

        whenever(localFolder.databaseId).thenReturn(SOURCE_FOLDER_ID)
    }

    @Test
    fun `archiveMessage should mark message as read and move it when option is enabled`() {
        whenever(account.isMarkMessageAsReadOnArchive).thenReturn(true)
        whenever(account.archiveFolderId).thenReturn(ARCHIVE_FOLDER_ID)

        val messageReference = MessageReference("accountUuid", SOURCE_FOLDER_ID, "uid")

        // Mock actOnMessagesGroupedByAccountAndFolder to immediately execute the actor
        doAnswer { invocation ->
            val actor = invocation.getArgument<MessageActor>(1)
            actor.act(account, localFolder, listOf(localMessage))
            null
        }.whenever(messagingController).actOnMessagesGroupedByAccountAndFolder(any(), any())

        // Mock putBackground to immediately execute the runnable
        doAnswer { invocation ->
            val runnable = invocation.getArgument<Runnable>(2)
            runnable.run()
            null
        }.whenever(messagingController).putBackground(any(), any(), any())

        archiveOperations.archiveMessage(messageReference)

        verify(messagingController).setFlag(eq(account), eq(SOURCE_FOLDER_ID), eq(listOf(localMessage)), eq(Flag.SEEN), eq(true))
        verify(messagingController).moveOrCopyMessageSynchronous(eq(account), eq(SOURCE_FOLDER_ID), eq(listOf(localMessage)), eq(ARCHIVE_FOLDER_ID), eq(MoveOrCopyFlavor.MOVE))
    }

    @Test
    fun `archiveMessage should NOT mark message as read when option is disabled`() {
        whenever(account.isMarkMessageAsReadOnArchive).thenReturn(false)
        whenever(account.archiveFolderId).thenReturn(ARCHIVE_FOLDER_ID)

        val messageReference = MessageReference("accountUuid", SOURCE_FOLDER_ID, "uid")

        doAnswer { invocation ->
            val actor = invocation.getArgument<MessageActor>(1)
            actor.act(account, localFolder, listOf(localMessage))
            null
        }.whenever(messagingController).actOnMessagesGroupedByAccountAndFolder(any(), any())

        doAnswer { invocation ->
            val runnable = invocation.getArgument<Runnable>(2)
            runnable.run()
            null
        }.whenever(messagingController).putBackground(any(), any(), any())

        archiveOperations.archiveMessage(messageReference)

        verify(messagingController, never()).setFlag(any(), any(), any<List<LocalMessage>>(), any(), any())
        verify(messagingController).moveOrCopyMessageSynchronous(eq(account), eq(SOURCE_FOLDER_ID), eq(listOf(localMessage)), eq(ARCHIVE_FOLDER_ID), eq(MoveOrCopyFlavor.MOVE))
    }

    companion object {
        const val SOURCE_FOLDER_ID = 1L
        const val ARCHIVE_FOLDER_ID = 2L
    }
}
